prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?target ?targetName ?targetType WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-FA205977-7AF8-4CB2-88A8-4C4CCE98E09D> .
  ?edge bbo:has_targetRef ?target .
  OPTIONAL { ?target bbo:name ?targetName . }
  OPTIONAL { ?target a ?targetType . }
}
